targets.expr:
sum(
  increase(
    grpc_server_handled_total{
      job="argocd-server-metrics",
      namespace=~"$namespace"
    }[$interval]
  )
) by (grpc_service)

sum(
  increase(
    grpc_server_handled_total{
      job="argocd-server-metrics",
      namespace=~"$namespace",
      grpc_code=~"Internal|Unavailable|DeadlineExceeded|ResourceExhausted"
    }[$interval]
  )
) by (grpc_service, grpc_code)

sum(
  increase(
    argocd_redis_request_total{
      namespace=~"$namespace",
      failed="true"
    }[$interval]
  )
) or vector(0)
